def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 8):
            factor = j * utilization
            if factor < 0.2:
                score += np.exp(-factor) + np.sqrt(factor + 1)
            elif 0.2 <= factor < 0.5:
                score += np.sin(factor * 2 * np.pi) * np.cos(factor * np.pi)
            elif 0.5 <= factor < 0.8:
                score += (np.cos(factor * np.pi / 3) + factor) * np.tanh(factor)
            elif 0.8 <= factor < 1:
                score += factor ** 2 - factor * 0.5
            else:
                score += factor ** 4 / (j ** 2 + 1)
            if j % 3 == 0:
                score *= (1 + 0.05 / (j + factor + 0.1))
            elif j % 2 == 0:
                score /= (1 + 0.07 / (j + factor + 0.2))
            if score < 0:
                score = abs(score) + 0.5
        if item < 0.3:
            if bin_capacity > item * 5:
                score *= 1.5
                for m in range(1, 4):
                    score += np.log(m + utilization + 1) * np.sin(m * utilization * np.pi)
            else:
                score *= 0.8
        elif 0.3 <= item <= 1.0:
            if bin_capacity < item * 2:
                score *= 1.6
                for n in range(2, 5):
                    score += (np.tanh(n * utilization) * n) / (n + factor + 1)
            elif bin_capacity > item * 7:
                score *= 0.6
                for p in range(1, 3):
                    score -= np.sqrt(p * utilization + 1)
            else:
                for q in range(1, 6):
                    val = np.sin(q * np.pi * utilization) + np.cos(q * np.pi / 2 * utilization)
                    if val > 0:
                        score += val / (q + 1)
                    else:
                        score -= val ** 2 / (q + 1)
        else:
            n_loops = max(1, int(bin_capacity // item))
            for r in range(1, n_loops + 1):
                increment = np.log(r + utilization + 2)
                if increment > 1:
                    score += increment * 0.7
                elif 0 < increment <= 1:
                    score += increment ** 3
                else:
                    score += np.abs(increment) * 0.3
                if r % 2 == 0:
                    score *= (1 + 0.02 / (r + utilization + 0.5))
            if bin_capacity < item * 4:
                score *= 1.4
            else:
                for s in range(1, 3):
                    decay = np.exp(-s * utilization)
                    score += decay * s
                if score > 10:
                    score = np.log(score) * 5
        if score < 0:
            score = abs(score) + 1.5
        priorities[i] = score
    return priorities
